```tcl
# factorial.tcl
# This script calculates the factorial of a given positive integer using recursion.
# It prompts the user for input and validates the input to ensure it is a positive integer.

# Function to calculate factorial recursively
proc factorial {n} {
    # Base case: factorial of 0 is 1
    if {$n == 0} {
        return 1
    } else {
        # Recursive case: n! = n * (n-1)!
        return [expr $n * [factorial [expr $n - 1]]]
    }
}

# Function to get a positive integer from the user
proc get_positive_integer {} {
    # Loop until a valid integer is entered
    while {1} {
        puts "Please enter a positive integer:"
        flush stdout  ;# Ensure the prompt is displayed before reading input

        # Read input
        set inputStr [gets stdin]

        # Check if the input is an integer
        if {[string is integer $inputStr] && $inputStr >= 0} {
            return $inputStr
        } else {
            puts "Invalid input! Please enter a non-negative integer."
        }
    }
}

# Main function to run the script
proc main {} {
    # Get a positive integer from the user
    set num [get_positive_integer]

    # Calculate the factorial
    set result [factorial $num]

    # Output the result
    puts "The factorial of $num is $result"
}

# Start the program
main
```

### Explanation:

1. **factorial proc**: This function calculates the factorial of a given integer `n` using recursion.
   - Base case: If `n` is 0, return 1 (since 0! = 1).
   - Recursive case: `n! = n * (n-1)!`.

2. **get_positive_integer proc**: This function prompts the user to enter a positive integer and validates the input.
   - It uses a loop to keep asking for input until a valid non-negative integer is entered.
   - The input is checked using `string is integer` to ensure it is a valid integer and greater than or equal to zero.

